module adder_32bit
(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [16:1] C1, C2;
wire [16:1] P, G;

assign P[1] = A[1] ^ B[1];
assign G[1] = A[1] & B[1];
assign C1[1] = G[1] | (P[1] & 1'b0);

generate
    genvar i;
    for (i = 2; i <= 16; i = i + 1) begin
        assign P[i] = A[i] ^ B[i];
        assign G[i] = A[i] & B[i];
        assign C1[i] = G[i] | (P[i] & C1[i-1]);
    end
endgenerate

assign P[17] = A[17] ^ B[17];
assign G[17] = A[17] & B[17];
assign C2[1] = G[17] | (P[17] & C1[16]);

generate
    genvar j;
    for (j = 18; j <= 32; j = j + 1) begin
        assign P[j] = A[j] ^ B[j];
        assign G[j] = A[j] & B[j];
        assign C2[j-16] = G[j] | (P[j] & C2[j-17]);
    end
endgenerate

assign S[1] = A[1] ^ B[1] ^ 1'b0;
assign S[32:2] = A[32:2] ^ B[32:2] ^ C1[16:1];
assign S[17] = A[17] ^ B[17] ^ C1[16];
assign S[32] = C2[32];
assign C32 = C2[32];

endmodule
